@@ -822,0 +821,11 @@
+      _stack.push(obj);
+    }
+  }
+
+  void drain() {
+    // Recurse with an external stack to avoid native stack overflow.
+    while (_stack.length() > 0) {
+      oop obj = _stack.pop();
+      _current = obj;
+      obj->oop_iterate(this);
+      _current = nullptr;
